<script setup lang="ts">
  import { Task } from '~~/models/task';

  const route = useRoute();
  const router = useRouter();
  const storeTask = await useStoreTask();

  let task = $ref<null | Task>(null);
  const id = $computed(() => route.params.id as string);

  watchEffect(async () => task = await taskGet(id));

  const STATE = {
    VIEW: 1,
    EDIT: 2,
    AVAILABILITY: 3,
    RELATIONS: 4,
    TAGS: 5,
  };

  let state = $ref(STATE.VIEW);

  let stateView = $computed(() => state === STATE.VIEW);

  let stateEdit = $computed({
    get() {
      return state === STATE.EDIT;
    },
    set(value) {
      state = value ? STATE.EDIT : STATE.VIEW;
    },
  });

  let stateAvailability = $computed({
    get() {
      return state === STATE.AVAILABILITY;
    },
    set(value) {
      state = value ? STATE.AVAILABILITY : STATE.VIEW;
    },
  });

  let stateRelations = $computed({
    get() {
      return state === STATE.RELATIONS;
    },
    set(value) {
      state = value ? STATE.RELATIONS : STATE.VIEW;
    },
  });

  let stateTags = $computed({
    get() {
      return state === STATE.TAGS;
    },
    set(value) {
      state = value ? STATE.TAGS : STATE.VIEW;
    },
  });

  async function taskDelete() {
    const { value: isConfirmed } = await Dialog.confirm({
      message: 'Are you sure you want to delete this task?',
    });
    if (!isConfirmed) return;
    await storeTask.taskDelete(id);
    router.push({ path: '/task/list' });
  }
</script>

<template>
  <Loading v-if="!task" />
  <NuxtLayout
    v-else
    name="common"
  >
    <template #header>
      <Button
        icon="fa6-solid:trash"
        flat
        @click="taskDelete"
      />
      <div class="flex-grow"></div>
      <div
        :class="[
          'pr-3',
          'flex',
          'flex-col',
          'items-end',
          'gap-1',
          'transition-opacity',
          'duration-300',
          { 'opacity-50': !task.isAvailable },
        ]"
      >
        <div
          :class="[
            'transition-all',
            'line-through',
            task.isAvailable ? 'decoration-transparent' : 'decoration-current',
            'text-primary',
          ]"
        >
          {{ task.title }}
        </div>
        <Progress
          :total="task.checklistTotal"
          :done="task.checklistDone"
        />
        <Availability
          :ms-switch-after="task.tsSwitchAt"
          :is-available="task.isAvailable"
        />
        <TaskTagsView
          v-if="!stateTags"
          :task="task"
        />
      </div>
    </template>
    <template #default>
      <div
        :key="state"
        class="px-4 pb-1"
      >
        <TaskTagsEdit
          v-if="stateTags"
          :task="task"
        />
        <ChecklistView
          v-if="stateView"
          key="checklist-view"
          :checklist="task.checklist"
        />
        <ChecklistEdit
          v-if="stateEdit"
          key="checklist-edit"
          v-model="task.checklist"
        />
        <EditorAvailability
          v-if="stateAvailability"
          key="availability"
          :available="task"
        />
        <EditorRelations
          v-if="stateRelations"
          key="relations"
          :task="task"
        />
      </div>
    </template>
    <template #footer>
      <Input
        v-if="stateEdit"
        v-model="task.title"
        flat
        class="flex-grow"
      />
      <div
        v-else
        class="flex-grow"
      ></div>
      <Toggle
        v-model="stateRelations"
        icon="fa6-solid:diagram-project"
        flat
      />
      <Toggle
        v-model="stateAvailability"
        icon="mdi:calendar-clock"
        flat
      />
      <Toggle
        v-model="stateTags"
        icon="fa6-solid:tags"
        flat
      />
      <Toggle
        v-model="stateEdit"
        icon="fa6-solid:pencil"
        flat
      />
      <Toggle
        v-if="!task.checklistTotal"
        v-model="task.isDone"
        icon="fa6-solid:check"
        flat
      />
    </template>
  </NuxtLayout>
</template>

<style lang="scss"></style>
