<script setup lang="ts">
  const { item } = defineProps<{
    item: ChecklistItem;
    isParentCompleted?: boolean;
  }>();

  const subitemsTotal = $computed(() => item[3].length);
  const subitemsDone = $computed(() => item[3].filter(e => e[1]).length);
  let unfold = $ref(false);

  const isCompleted = $computed(() =>
    subitemsTotal ? subitemsDone === subitemsTotal : item[1],
  );

  watch(
    [$$(isCompleted), $$(subitemsTotal)],
    () => {
      if (!subitemsTotal) return;
      item[1] = isCompleted;
    },
    { immediate: true },
  );

  function toggle() {
    if (subitemsTotal) {
      unfold = !unfold;
      return;
    }
    item[1] = !item[1];
  }
</script>

<template>
  <li
    :class="[
      'flex-grow',
      { 'opacity-50': !isParentCompleted && isCompleted },
      'list-none',
      'relative',
      'pl-5',
    ]"
  >
    <TransitionHeight v-model="unfold">
      <ChecklistView
        :checklist="item[3]"
        class="-ml-1.5 pl-2 pt-1 border-t border-l rounded-tl border-secondary/20"
        :is-parent-completed="isParentCompleted || isCompleted"
      />
    </TransitionHeight>
    <div
      class="p-2 flex justify-between items-end"
      @click="toggle()"
    >
      <div
        :class="[
          'transition-all',
          isCompleted ? 'decoration-current' : 'decoration-transparent',
          'line-through',
          'relative',
        ]"
      >
        <span
          class="absolute top-0 -left-6 w-6 flex items-center justify-center"
        >
          <Icon
            :name="subitemsTotal ? 'fa6-solid:chevron-up' : 'fa6-solid:circle'"
            :class="[
              'transition-transform duration-[600ms]',
              subitemsTotal ? 'text-[10px]' : 'text-[6px]',
              { 'rotate-90': !unfold },
            ]"
          />&nbsp;
        </span>
        {{ item[0] }}
      </div>
      <div>
        <Progress
          :done="subitemsDone"
          :total="subitemsTotal"
        />
      </div>
    </div>
  </li>
</template>

<style lang="scss"></style>
