<script setup lang="ts">
  import { UnwrapRef } from 'vue';
  import { Task } from '~~/models/task';

  const { task } = defineProps<{ task: UnwrapRef<Task> }>();

  const storeTask = await useStoreTask();

  let tasks = $ref([] as [Task, boolean, boolean][]);
  watchEffect(async () => {
    tasks = await Promise.all(
      storeTask.tasks.map(
        async t =>
          [
            t,
            !await task.relations.hasInDirectSuccessors(t.id),
            !await task.relations.hasInDirectPredecessors(t.id),
          ] as [UnwrapRef<Task>, boolean, boolean],
      ),
    );
  });
</script>

<template>
  <div v-auto-animate="{ duration: 300 }">
    <Label
      label="Relations"
      class="flex flex-col gap-2 pb-2"
    >
      <template
        v-for="[t, canPred, canSucc] in tasks"
        :key="t.id"
      >
        <EditorRelationsRow
          :relations="task.relations"
          :row="t"
          :can-pred="canPred"
          :can-succ="canSucc"
        />
      </template>
    </Label>
  </div>
</template>

<style lang="scss"></style>
