<script setup lang="ts">
  const { checklist } = defineProps<{
    checklist: Checklist;
    isParentCompleted?: boolean;
  }>();

  watch(
    $$(checklist),
    () =>
      checklist.sort(
        (a, b) =>
          +b[1] - +a[1] ||
          a[3].length - b[3].length ||
          checklist.indexOf(a) - checklist.indexOf(b),
      ),
    { deep: true, immediate: true },
  );
</script>

<template>
  <TransitionFade
    group
    tag="ul"
    class="flex flex-col gap-1 select-none"
  >
    <ChecklistViewItem
      v-for="item in checklist"
      :key="item[2]"
      :item="item"
      :is-parent-completed="isParentCompleted"
    />
  </TransitionFade>
</template>

<style lang="scss"></style>
