<script setup lang="ts">
  import { UnwrapRef } from 'vue';
  import { Relations } from '~~/utils/relations';

  type T = {
    id: string;
    isDirty: boolean;
    data: { predecessors: string[]; successors: string[] };
    relations: Relations<T>;
    dateTimeUpdated: null | Temporal.PlainDateTime;
  };

  const { relations, row, canSucc } = defineProps<{
    relations: UnwrapRef<Relations<T>>;
    row: UnwrapRef<T>;
    canSucc: boolean;
    canPred: boolean;
  }>();

  const isSucc = $computed({
    get() {
      return relations.hasSuccessor(row);
    },
    set(value) {
      value ? relations.addSuccessor(row) : relations.removeSuccessor(row);
    },
  });
  const isPred = $computed({
    get() {
      return relations.hasPredecessor(row);
    },
    set(value) {
      value ? relations.addPredecessor(row) : relations.removePredecessor(row);
    },
  });
</script>

<template>
  <div
    v-if="canPred || canSucc"
    class="flex gap-4 items-center"
  >
    <Toggle
      v-model="isPred"
      :disabled="!canPred || isSucc"
      icon="fa6-solid:diagram-predecessor"
    />
    <div class="flex-grow">
      <template v-if="'title' in row">
        {{ row.title }}
      </template>
      <template v-else-if="'name' in row">
        {{ row.name }}
      </template>
    </div>
    <Toggle
      v-model="isSucc"
      :disabled="!canSucc || isPred"
      icon="fa6-solid:diagram-successor"
    />
  </div>
</template>

<style lang="scss"></style>
