<script setup lang="ts">
  const { modelValue, duration = 300 } = defineProps<{
    modelValue: boolean;
    duration?: number;
  }>();

  let show = $ref(modelValue);
  let height = $ref('auto');
  let opacity = $ref(1);

  const el = ref<null | HTMLElement>(null);

  watch(
    $$(modelValue),
    async () => {
      if (modelValue) {
        show = true;
        height = 'auto';
        await nextTick();
        const rect = el.value?.getBoundingClientRect() ?? { height: 0 };
        height = '0';
        await animationFrame();
        height = `${rect.height}px`;
        await timeout(duration);
        height = 'auto';
        opacity = 0;
        await animationFrame();
        opacity = 1;
      } else {
        const rect = el.value?.getBoundingClientRect() ?? { height: 0 };
        height = `${rect.height}px`;
        opacity = 0;
        await timeout(duration);
        height = `0`;
        await timeout(duration);
        show = false;
      }
    },
    { immediate: true },
  );
</script>

<template>
  <div
    v-if="show"
    ref="el"
    :style="{ height, opacity, 'transition-duration': `${duration}ms` }"
    class="transition-all ease-in-out"
  >
    <slot></slot>
  </div>
</template>

<style lang="scss" scoped></style>
