<script setup lang="ts">
  const id = `_${createId()}`;

  const { modelValue } = defineProps<{
    modelValue: Checklist;
  }>();

  const emit = defineEmits<{
    (event: 'update:modelValue', value: Checklist): void;
  }>();

  let checklist = $computed({
    get() {
      modelValue.sort((a, b) => +b[1] - +a[1]);
      return modelValue;
    },
    set(value) {
      emit('update:modelValue', value);
    },
  });

  function refresh() {
    checklist = reactive([...checklist]);
  }

  function addItem() {
    checklist.push([newItem, false, createId(), []]);
    refresh();
    newItem = '';
    document.getElementById(id)?.focus();
  }

  let newItem = $ref('');
</script>

<template>
  <div v-auto-animate="{ duration: 300 }">
    <ChecklistEditItem
      v-for="(item, index) in checklist"
      :key="item[2]"
      :item="item"
      @refresh="refresh()"
      @remove="checklist = checklist.filter((_, i) => i !== index)"
    />
    <div
      v-auto-animate="{ duration: 300 }"
      class="relative flex items-start gap-2"
    >
      <Input
        :id="id"
        v-model="newItem"
        class="flex-grow flex-shrink"
        placeholder="Add list item"
        flat
        autogrow
      />
      <Button
        v-if="newItem"
        icon="fa6-solid:plus"
        flat
        class="pr-0"
        @click="addItem()"
      />
    </div>
  </div>
</template>

<style lang="scss"></style>
