<script setup lang="ts">
  const { item } = defineProps<{
    item: ChecklistItem;
    isParentCompleted?: boolean;
  }>();

  const emit = defineEmits<{
    (event: 'refresh'): void;
    (event: 'remove'): void;
  }>();

  const subitemsTotal = $computed(() => item[3].length);
  const subitemsDone = $computed(() => item[3].filter(e => e[1]).length);

  const isCompleted = $computed(() =>
    subitemsTotal ? subitemsDone === subitemsTotal : item[1],
  );

  watch(
    [$$(isCompleted), $$(subitemsTotal)],
    () => {
      if (!subitemsTotal) return;
      item[1] = isCompleted;
    },
    { immediate: true },
  );
</script>

<template>
  <div>
    <ChecklistEdit
      v-model="item[3]"
      class="ml-3.5 mt-2 pl-[1.375rem] border-t border-l rounded-tl border-secondary/20"
      @update:model-value="emit('refresh')"
    />
    <div
      :class="['flex', 'items-start', { 'line-through opacity-50': item[1] }]"
    >
      <Button
        icon="fa6-solid:xmark"
        flat
        class="pl-0"
        @click="emit('remove')"
      />
      <Input
        v-model="item[0]"
        flat
        :class="['flex-grow', 'flex-shrink']"
        autogrow
      />
    </div>
  </div>
</template>

<style lang="scss"></style>
