<script setup lang="ts">
  import { Task } from '@/models/task';
  import { UnwrapRef } from 'vue';

  const { task } = defineProps<{
    task: UnwrapRef<Task>;
    showTags?: boolean;
  }>();

  const storeTag = await useStoreTag();
</script>

<template>
  <div class="flex mt-1 gap-2 text-[.5rem] items justify-end flex-wrap">
    <Toggle
      v-for="tag in storeTag.tags"
      :key="tag.id"
      :model-value="tag.data.tasks.includes(task.id)"
      :class="[
        'whitespace-nowrap',
        '!h-auto',
        '!px-2',
        '!py-1',
        'rounded-full',
        { 'opacity-50': !tag.isAvailable },
      ]"
      :label="tag.name"
      @update:model-value="
        v => {
          if (v) {
            tag.taskAdd(task);
          } else {
            tag.taskRemove(task);
          }
        }
      "
    />
  </div>
</template>

<style lang="scss"></style>
